    ["Use Teleporter"] = "Используйте телепорт",
    ["Valeera on Left"] = "Валира слева",
    ["Vault of the Incarnates: Break a Few Eggs"] = "Хранилище Воплощений – вынужденные меры",
    ["Vent"] = "Вентиляция",
    ["Vent Behind Neltharion then Jump"] = "Вентиляция позади Нелтариона, затем прыжок",
